<?php $ch = curl_init("http://document_tracking_system.test/api/permissions"); curl_setopt($ch, CURLOPT_POST, 1); curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode(["department" => "IT Center", "type" => "Super Admin", "permissions" => ["Request" => ["Create" => true]]])); curl_setopt($ch, CURLOPT_HTTPHEADER, ["Content-Type: application/json", "Accept: application/json"]); curl_setopt($ch, CURLOPT_RETURNTRANSFER, true); $res = curl_exec($ch); $json = json_decode($res, true); echo $json["message"] ?? "No message"; echo "\n"; echo $json["exception"] ?? "No exception";
